/* ── Embedded IOL white logo (1324x1012 JPEG, ratio 1.308) ── */
const LOGO_B64 = 'data:image/jpeg;base64,';
let _logo = null;
function getLogo() {
  return new Promise(res => {
    if (_logo) { res(_logo); return; }
    const i = new Image();
    i.onload  = () => { _logo = i; res(i); };
    i.onerror = () => res(null);
    i.src = LOGO_B64;
  });
}

