/* ── App state ── */
let allStories  = [];
let curFilter   = 'all';
let visible     = PAGE_SZ;
let doneIds     = new Set(JSON.parse(localStorage.getItem('iol_done') || '[]'));

/* ── Designer state ── */
const S = 1080;
let d = {
  type:'single', cat:'news', kicker:'BREAKING NEWS', headline:'', caption:'',
  imgUrl:'', imgEl:null, imgX:0, imgY:0, imgScale:1,
  textPos:'mid', storyUrl:'', shortUrl:'',
  slides:[], slide:0,
  dragging:false, dsx:0, dsy:0, dox:0, doy:0,
  storyId:null,
};

function saveDone() { localStorage.setItem('iol_done', JSON.stringify([...doneIds])); }
function relTime(s) {
  if (!s) return 'Today';
  try { const m = Math.floor((Date.now() - new Date(s)) / 60000); if (m<1) return 'Just now'; if (m<60) return m+'m ago'; if (m<1440) return Math.floor(m/60)+'h ago'; return 'Today'; } catch { return 'Today'; }
}
function esc(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#039;'); }
function $id(id) { return document.getElementById(id); }
function gv(id) { const e=$id(id); return e?e.value:''; }
function sv(id,v) { const e=$id(id); if(e)e.value=v||''; }

/* ════════════════════════════════════════════
   FEED
   ════════════════════════════════════════════ */
async function loadStories(refresh) {
  const grid=$id('stories-grid'), status=$id('feed-status'), btn=$id('refresh-btn');
  if (btn) btn.classList.add('spin');
  if (refresh) visible = PAGE_SZ;
  if (grid) grid.innerHTML = '<div class="grid-loading"><div class="spinner"></div><p>Loading latest IOL stories…</p></div>';

  try {
    const res  = await fetch(WORKER + '/all', { signal: AbortSignal.timeout(12000) });
    const data = await res.json();
    if (!data.ok || !data.stories || data.stories.length < 3) throw new Error('empty');
    allStories = data.stories.map((s, i) => ({
      id: 'live-'+i, cat: s.category || 'news', headline: s.headline,
      excerpt: s.excerpt||'', source: s.source||'IOL',
      time: relTime(s.pubDate), url: s.url||'https://www.iol.co.za', image: s.image||''
    }));
    if (status) { status.textContent = allStories.length + ' stories · live'; status.className='feed-status'; }
  } catch(_) {
    allStories = [...PRELOADED];
    if (status) { status.textContent = allStories.length + ' stories · cached'; status.className='feed-status'; }
  }

  renderFeed();
  if (btn) btn.classList.remove('spin');
}

function renderFeed() {
  const grid = $id('stories-grid');
  if (!grid) return;
  const filt = curFilter === 'all' ? allStories : allStories.filter(s => {
    // Group entertainment + lifestyle under 'leisure'
    if (curFilter === 'leisure') return ['entertainment','lifestyle','leisure'].includes(s.cat);
    return s.cat === curFilter;
  });
  const vis = filt.slice(0, visible);

  if (!vis.length) {
    grid.innerHTML = '<div class="grid-loading"><p>No stories in this category.</p></div>';
    if ($id('load-more-row')) $id('load-more-row').style.display = 'none';
    return;
  }

  grid.innerHTML = vis.map(s => `
    <div class="scard${doneIds.has(s.id)?' done':''}" data-id="${esc(s.id)}">
      <div class="scard-cat">${esc(s.cat==='entertainment'||s.cat==='lifestyle'?'Leisure':s.cat)}</div>
      <div class="scard-hl">${esc(s.headline)}</div>
      ${s.excerpt ? `<div class="scard-ex">${esc(s.excerpt)}</div>` : ''}
      <div class="scard-meta">
        <span class="scard-src">${esc(s.source)}</span>
        <span>·</span>
        <span>${esc(s.time)}</span>
        <span class="scard-cta">Make card →</span>
      </div>
    </div>
  `).join('');

  grid.querySelectorAll('.scard').forEach(c => {
    c.addEventListener('click', () => {
      const story = allStories.find(s => s.id === c.dataset.id);
      if (story) openDesigner(story);
    });
  });

  const lmr = $id('load-more-row');
  if (lmr) lmr.style.display = filt.length > visible ? 'block' : 'none';
}

/* Filter pills */
$id('cat-pills')?.addEventListener('click', e => {
  const p = e.target.closest('.cpill');
  if (!p) return;
  document.querySelectorAll('.cpill').forEach(x => x.classList.remove('active'));
  p.classList.add('active');
  curFilter = p.dataset.cat;
  visible = PAGE_SZ;
  renderFeed();
});
$id('load-more-btn')?.addEventListener('click', () => { visible += PAGE_SZ; renderFeed(); });
$id('refresh-btn')?.addEventListener('click', () => loadStories(true));

/* ════════════════════════════════════════════
   DESIGNER — OPEN / CLOSE
   ════════════════════════════════════════════ */
async function openDesigner(story) {
  // Reset state from story
  d.cat      = story.cat || 'news';
  d.kicker   = autoKicker(story.headline, story.cat);
  d.headline = story.headline || '';
  d.caption  = story.excerpt  || '';
  d.imgUrl   = story.image    || '';
  d.storyUrl = story.url      || '';
  d.shortUrl = '';
  d.imgX=0; d.imgY=0; d.imgScale=1;
  d.textPos  = 'mid';
  d.type     = 'single';
  d.slides   = [];
  d.slide    = 0;
  d.imgEl    = null;
  d.storyId  = story.id;

  // Set UI
  sv('ctrl-cat',     d.cat);
  sv('ctrl-kicker',  d.kicker);
  sv('ctrl-headline',d.headline);
  sv('ctrl-caption', d.caption);
  sv('ctrl-imgurl',  d.imgUrl);
  document.querySelectorAll('.tt-btn').forEach(b => b.classList.toggle('active', b.dataset.type==='single'));
  document.querySelectorAll('.pos-btn').forEach(b => b.classList.toggle('active', b.dataset.pos==='mid'));
  if ($id('dnav-title')) $id('dnav-title').textContent = story.headline;
  updateCarouselUI();
  buildShareText();

  // Open
  $id('designer').classList.add('open');
  document.body.style.overflow = 'hidden';

  // Draw immediately with dark bg
  await waitPoppins();
  renderCard();

  // Load image via worker proxy
  if (d.imgUrl) {
    const proxy = WORKER + '/image?url=' + encodeURIComponent(d.imgUrl);
    d.imgEl = await loadImgCORS(proxy);
    if (!d.imgEl) d.imgEl = await loadImgDirect(d.imgUrl);
    renderCard();
  }

  // Shorten URL in background
  if (d.storyUrl) {
    try {
      const r = await fetch(WORKER + '/shorten?url=' + encodeURIComponent(d.storyUrl));
      const j = await r.json();
      if (j.ok && j.short) { d.shortUrl = j.short; buildShareText(); }
    } catch(_) {}
  }
}

$id('back-btn')?.addEventListener('click', () => {
  $id('designer').classList.remove('open');
  document.body.style.overflow = '';
  renderFeed();
});

function autoKicker(h, c) {
  if (!h) return (cfg(c).lbl);
  return h.split(' ').slice(0,3).join(' ').toUpperCase();
}

/* ════════════════════════════════════════════
   DESIGNER CONTROLS
   ════════════════════════════════════════════ */
function curSlide() { return d.type==='carousel' && d.slides.length>0 ? d.slides[d.slide] : d; }

['ctrl-kicker','ctrl-headline','ctrl-caption','ctrl-cat'].forEach(id => {
  $id(id)?.addEventListener('input', function() {
    const sl = curSlide();
    if (id==='ctrl-kicker')   { d.kicker   =this.value; sl.kicker  =this.value; }
    if (id==='ctrl-headline') { d.headline =this.value; sl.headline=this.value; }
    if (id==='ctrl-caption')  { d.caption  =this.value; sl.caption =this.value; }
    if (id==='ctrl-cat')      { d.cat      =this.value; if(sl!==d)sl.cat=this.value; }
    renderCard();
  });
});

$id('ctrl-imgurl')?.addEventListener('change', reloadImg);
$id('ctrl-reload')?.addEventListener('click',  reloadImg);

async function reloadImg() {
  const url = gv('ctrl-imgurl').trim();
  d.imgUrl = url; d.imgX=0; d.imgY=0; d.imgScale=1; d.imgEl=null;
  if (url) {
    d.imgEl = await loadImgCORS(WORKER+'/image?url='+encodeURIComponent(url));
    if (!d.imgEl) d.imgEl = await loadImgDirect(url);
  }
  const sl = curSlide();
  if (sl!==d) { sl.imgUrl=url; sl.imgEl=d.imgEl; sl.imgX=0; sl.imgY=0; sl.imgScale=1; }
  renderCard();
}

$id('pos-grid')?.addEventListener('click', e => {
  const b = e.target.closest('.pos-btn');
  if (!b) return;
  document.querySelectorAll('.pos-btn').forEach(x=>x.classList.remove('active'));
  b.classList.add('active');
  d.textPos = b.dataset.pos;
  renderCard();
});

$id('type-toggle')?.addEventListener('click', e => {
  const b = e.target.closest('.tt-btn');
  if (!b) return;
  document.querySelectorAll('.tt-btn').forEach(x=>x.classList.remove('active'));
  b.classList.add('active');
  d.type = b.dataset.type;
  if (d.type==='carousel' && d.slides.length===0) addSlide();
  $id('btn-dl-all').style.display = d.type==='carousel' ? 'inline-block' : 'none';
  updateCarouselUI(); renderCard();
});

function addSlide() {
  d.slides.push({kicker:d.kicker,headline:d.headline,caption:d.caption,cat:d.cat,imgUrl:d.imgUrl,imgEl:d.imgEl,imgX:0,imgY:0,imgScale:1});
  d.slide = d.slides.length-1;
}
function syncSlideUI() {
  const sl = d.slides[d.slide]; if(!sl)return;
  sv('ctrl-kicker',sl.kicker); sv('ctrl-headline',sl.headline);
  sv('ctrl-caption',sl.caption); sv('ctrl-cat',sl.cat||d.cat); sv('ctrl-imgurl',sl.imgUrl||'');
}
function updateCarouselUI() {
  const bar=$id('carousel-bar'), ind=$id('c-indicator');
  const isC = d.type==='carousel';
  if(bar) bar.style.display = isC?'flex':'none';
  if(ind) ind.textContent = isC?`Slide ${d.slide+1} / ${d.slides.length}`:'';
}

$id('c-add')?.addEventListener('click', ()=>{ addSlide(); updateCarouselUI(); renderCard(); });
$id('c-del')?.addEventListener('click', ()=>{
  if(d.slides.length<=1)return;
  d.slides.splice(d.slide,1); d.slide=Math.min(d.slide,d.slides.length-1);
  syncSlideUI(); updateCarouselUI(); renderCard();
});
$id('c-prev')?.addEventListener('click',()=>{ if(d.slide>0){d.slide--;syncSlideUI();updateCarouselUI();renderCard();} });
$id('c-next')?.addEventListener('click',()=>{ if(d.slide<d.slides.length-1){d.slide++;syncSlideUI();updateCarouselUI();renderCard();} });

/* Image toolbar */
$id('itb-zoom-in')?.addEventListener('click',  ()=>{ const sl=curSlide(); sl.imgScale=Math.min(3,(sl.imgScale||1)+0.1); if(sl!==d)d.imgScale=sl.imgScale; renderCard(); });
$id('itb-zoom-out')?.addEventListener('click', ()=>{ const sl=curSlide(); sl.imgScale=Math.max(0.2,(sl.imgScale||1)-0.1); if(sl!==d)d.imgScale=sl.imgScale; renderCard(); });
$id('itb-reset')?.addEventListener('click',   ()=>{ const sl=curSlide(); sl.imgX=0;sl.imgY=0;sl.imgScale=1; if(sl!==d){d.imgX=0;d.imgY=0;d.imgScale=1;} renderCard(); });

/* Drag canvas */
const canvas = $id('card-canvas');
if (canvas) {
  canvas.addEventListener('mousedown', e=>{
    d.dragging=true; d.dsx=e.clientX; d.dsy=e.clientY;
    const sl=curSlide(); d.dox=sl.imgX||0; d.doy=sl.imgY||0; e.preventDefault();
  });
  window.addEventListener('mousemove', e=>{
    if(!d.dragging)return;
    const r=canvas.getBoundingClientRect(), sx=S/r.width;
    const sl=curSlide(); sl.imgX=d.dox+(e.clientX-d.dsx)*sx; sl.imgY=d.doy+(e.clientY-d.dsy)*sx;
    if(sl!==d){d.imgX=sl.imgX;d.imgY=sl.imgY;}
    renderCard();
  });
  window.addEventListener('mouseup',()=>{ d.dragging=false; });
  canvas.addEventListener('wheel', e=>{
    e.preventDefault();
    const sl=curSlide(); sl.imgScale=Math.max(0.2,Math.min(3,(sl.imgScale||1)-e.deltaY*0.001));
    if(sl!==d)d.imgScale=sl.imgScale; renderCard();
  },{passive:false});
  canvas.addEventListener('touchstart',e=>{
    if(e.touches.length!==1)return;
    d.dragging=true; d.dsx=e.touches[0].clientX; d.dsy=e.touches[0].clientY;
    const sl=curSlide(); d.dox=sl.imgX||0; d.doy=sl.imgY||0;
  },{passive:true});
  canvas.addEventListener('touchmove',e=>{
    if(!d.dragging||e.touches.length!==1)return;
    const r=canvas.getBoundingClientRect(),sx=S/r.width;
    const sl=curSlide(); sl.imgX=d.dox+(e.touches[0].clientX-d.dsx)*sx; sl.imgY=d.doy+(e.touches[0].clientY-d.dsy)*sx;
    renderCard();
  },{passive:true});
  canvas.addEventListener('touchend',()=>{ d.dragging=false; });
}

/* Download */
$id('btn-dl')?.addEventListener('click', ()=>{ markDone(); dlCanvas('iol-card.png'); });
$id('btn-dl-all')?.addEventListener('click', async ()=>{
  markDone();
  if(d.type!=='carousel'||!d.slides.length){dlCanvas('iol-card.png');return;}
  for(let i=0;i<d.slides.length;i++){
    d.slide=i; syncSlideUI(); updateCarouselUI(); await renderCard();
    dlCanvas('iol-slide-'+String(i+1).padStart(2,'0')+'.png');
    await new Promise(r=>setTimeout(r,250));
  }
});
function markDone() { if(d.storyId){doneIds.add(d.storyId);saveDone();} }
function dlCanvas(fn) {
  const c=$id('card-canvas'); if(!c)return;
  try { const a=document.createElement('a');a.href=c.toDataURL('image/png');a.download=fn;a.click(); }
  catch(e){ alert('Right-click the card and choose "Save image as".'); }
}

/* Share text */
$id('copy-share-btn')?.addEventListener('click', function() {
  const t=gv('ctrl-share'); if(!t)return;
  navigator.clipboard.writeText(t).then(()=>{ const o=this.textContent;this.textContent='Copied!';setTimeout(()=>this.textContent=o,1600); });
});
function buildShareText() {
  const cc = cfg(d.cat);
  const isLeisure = cc.style === 'leisure';
  const tagMap = {
    news:'#SouthAfrica #NewsZA #IOL', politics:'#SAPoltics #SouthAfrica #IOL',
    sport:'#SportZA #SouthAfrica #IOL', business:'#BusinessZA #SouthAfrica #IOL',
    technology:'#TechZA #SouthAfrica #IOL', entertainment:'#Leisure #Entertainment #IOL',
    lifestyle:'#Leisure #Lifestyle #IOL', motoring:'#Motoring #SouthAfrica #IOL',
    travel:'#Travel #SouthAfrica #IOL',
  };
  const tags = tagMap[d.cat] || '#SouthAfrica #IOL';
  const url  = d.shortUrl || d.storyUrl;
  const urlLine = url ? '\n\n\uD83D\uDD17 ' + url : '';
  sv('ctrl-share', d.headline + urlLine + '\n\n' + tags + '\n\n\uD83D\uDCF0 Follow @IOL' + (isLeisure?' Leisure':'')+' for the latest news');
}

/* ════════════════════════════════════════════
   CANVAS RENDERER
   ════════════════════════════════════════════ */
async function renderCard() {
  const c = $id('card-canvas'); if(!c)return;
  c.width=S; c.height=S;
  const ctx = c.getContext('2d');
  const sl  = curSlide();
  const logo = await getLogo();
  const p = {
    kicker:   sl.kicker   || d.kicker   || '',
    headline: sl.headline || d.headline || '',
    caption:  sl.caption  || d.caption  || '',
    cat:      sl.cat      || d.cat      || 'news',
    imgEl:    sl.imgEl    || d.imgEl,
    imgX:     sl.imgX  != null ? sl.imgX  : d.imgX,
    imgY:     sl.imgY  != null ? sl.imgY  : d.imgY,
    imgScale: sl.imgScale || d.imgScale  || 1,
    textPos:  d.textPos   || 'mid',
    logo,
  };
  const cc = cfg(p.cat);
  if (cc.style === 'leisure') drawLeisureCard(ctx, p, cc);
  else                         drawStandardCard(ctx, p, cc);
}

/* ── STANDARD CARD ─────────────────────────────────
   Full-bleed photo, dark gradient, white kicker box
   top-left, bold white headline + caption centred,
   IOL logo + coloured pill bottom-centre (LOCKED)  ── */
function drawStandardCard(ctx, p, cc) {
  ctx.fillStyle='#0D0D0D'; ctx.fillRect(0,0,S,S);

  // Photo
  if (p.imgEl) {
    ctx.save(); ctx.beginPath(); ctx.rect(0,0,S,S); ctx.clip();
    const sc=Math.max(S/p.imgEl.width,S/p.imgEl.height)*(p.imgScale||1);
    ctx.drawImage(p.imgEl,(S-p.imgEl.width*sc)/2+p.imgX,(S-p.imgEl.height*sc)/2+p.imgY,p.imgEl.width*sc,p.imgEl.height*sc);
    ctx.restore();
  }

  // Gradient overlay
  const g=ctx.createLinearGradient(0,0,0,S);
  g.addColorStop(0,'rgba(0,0,0,0.15)'); g.addColorStop(0.38,'rgba(0,0,0,0.38)');
  g.addColorStop(0.65,'rgba(0,0,0,0.58)'); g.addColorStop(1,'rgba(0,0,0,0.82)');
  ctx.fillStyle=g; ctx.fillRect(0,0,S,S);

  // Left accent strip
  ctx.fillStyle=cc.col; ctx.fillRect(0,0,6,S);

  // Kicker box top-left
  ctx.save();
  ctx.font='800 30px Poppins,Arial Black,sans-serif'; ctx.textBaseline='middle';
  const kt=(p.kicker||'').toUpperCase(), kw=ctx.measureText(kt).width+40, kh=52, kx=48, ky=52;
  ctx.fillStyle='rgba(0,0,0,0.22)'; ctx.fillRect(kx,ky,kw,kh);
  ctx.strokeStyle='rgba(255,255,255,0.8)'; ctx.lineWidth=2; ctx.strokeRect(kx,ky,kw,kh);
  ctx.fillStyle='#fff'; ctx.fillText(kt,kx+20,ky+kh/2);
  ctx.restore();

  // Headline + caption block
  ctx.save();
  ctx.font='800 60px Poppins,Arial Black,sans-serif'; ctx.textAlign='center'; ctx.textBaseline='alphabetic';
  const hlLines=wrapText(ctx,p.headline||'',S-96), hlLH=74;
  ctx.font='500 36px Poppins,Arial,sans-serif';
  const capLines=p.caption?wrapText(ctx,p.caption,S-120):[], capLH=48, gap=20;
  const logoZone=110, totalH=hlLines.length*hlLH+(capLines.length?gap+capLines.length*capLH:0);
  const topY=180, botY=S-logoZone-totalH-40, midY=(S-logoZone-totalH)/2+20;
  const blockTop = p.textPos==='top'?topY : p.textPos==='bot'?botY : midY;

  ctx.font='800 60px Poppins,Arial Black,sans-serif'; ctx.fillStyle='#fff';
  hlLines.forEach((ln,i)=>ctx.fillText(ln,S/2,blockTop+(i+1)*hlLH));
  if(capLines.length){
    ctx.font='500 36px Poppins,Arial,sans-serif'; ctx.fillStyle='rgba(255,255,255,0.90)';
    const ct=blockTop+hlLines.length*hlLH+gap;
    capLines.forEach((ln,i)=>ctx.fillText(ln,S/2,ct+(i+1)*capLH));
  }
  ctx.restore();

  // IOL logo + pill (LOCKED)
  drawLogoAndPill(ctx, p.logo, cc);
}

/* ── LEISURE CARD ─────────────────────────────────
   Matches the FacebookX_Post.png template:
   - Heavy dark/purple gradient bottom half
   - Headline: large bold, LEFT-ALIGNED, hot pink
   - White rule line below headline
   - Caption: white, left-aligned, below rule
   - IOL logo top-left + "Leisure" teal italic below  ── */
function drawLeisureCard(ctx, p, cc) {
  ctx.fillStyle='#1A0E18'; ctx.fillRect(0,0,S,S);

  // Photo (top portion — upper half)
  if (p.imgEl) {
    ctx.save(); ctx.beginPath(); ctx.rect(0,0,S,S); ctx.clip();
    const sc=Math.max(S/p.imgEl.width,S/p.imgEl.height)*(p.imgScale||1);
    ctx.drawImage(p.imgEl,(S-p.imgEl.width*sc)/2+p.imgX,(S-p.imgEl.height*sc)/2+p.imgY,p.imgEl.width*sc,p.imgEl.height*sc);
    ctx.restore();
  }

  // Heavy gradient — purple/magenta tinted like the template
  const g=ctx.createLinearGradient(0,0,0,S);
  g.addColorStop(0,   'rgba(20,8,18,0.0)');
  g.addColorStop(0.30,'rgba(20,8,18,0.25)');
  g.addColorStop(0.52,'rgba(20,8,18,0.72)');
  g.addColorStop(0.70,'rgba(20,8,18,0.90)');
  g.addColorStop(1,   'rgba(20,8,18,0.97)');
  ctx.fillStyle=g; ctx.fillRect(0,0,S,S);

  // ── IOL logo top-left ──
  if (p.logo) {
    const lw=72, lh=55;
    ctx.drawImage(p.logo, 48, 44, lw, lh);
  }
  // "Leisure" teal italic text below logo
  ctx.save();
  ctx.font='italic 600 34px Georgia,"Times New Roman",serif';
  ctx.fillStyle='#4ED8D8'; // teal
  ctx.textBaseline='top'; ctx.textAlign='left';
  ctx.fillText('Leisure', 48, 104);
  ctx.restore();

  // ── Headline: hot pink, bold, left-aligned, large ──
  const padL=56, maxW=S-padL*2;
  const textY = p.textPos==='top' ? 240 : p.textPos==='bot' ? 480 : 360;
  ctx.save();
  ctx.font='900 72px Poppins,Arial Black,sans-serif'; ctx.textAlign='left'; ctx.textBaseline='alphabetic';
  ctx.fillStyle='#F06BB5'; // hot pink matching #E97DC0 approx
  const hlLines=wrapText(ctx,p.headline||'',maxW), hlLH=82;
  hlLines.forEach((ln,i)=>ctx.fillText(ln,padL,textY+(i+1)*hlLH));

  // Rule line (white, short, below headline)
  const ruleY = textY + hlLines.length*hlLH + 22;
  ctx.strokeStyle='#FFFFFF'; ctx.lineWidth=3;
  ctx.beginPath(); ctx.moveTo(padL,ruleY); ctx.lineTo(padL+240,ruleY); ctx.stroke();

  // Caption: white, regular, left-aligned
  if (p.caption) {
    ctx.font='400 38px Poppins,Arial,sans-serif'; ctx.fillStyle='rgba(255,255,255,0.92)';
    const capLines=wrapText(ctx,p.caption,maxW), capLH=52;
    capLines.forEach((ln,i)=>ctx.fillText(ln,padL,ruleY+36+(i+1)*capLH));
  }
  ctx.restore();
}

function drawLogoAndPill(ctx, logo, cc) {
  // Logo: 1324x1012 JPEG ratio 1.308 → at height=52, width=68
  const lw=68, lh=52, cx=S/2, ly=S-112;
  if (logo) { ctx.drawImage(logo,Math.round(cx-lw/2),Math.round(ly),lw,lh); }
  else {
    ctx.save(); ctx.fillStyle=cc.col;
    ctx.beginPath(); ctx.moveTo(cx-40,ly+4); ctx.lineTo(cx-40,ly+36); ctx.lineTo(cx-24,ly+4); ctx.closePath(); ctx.fill();
    ctx.font='900 32px Poppins,sans-serif'; ctx.fillStyle='#fff'; ctx.textAlign='center'; ctx.textBaseline='top'; ctx.fillText('IOL',cx+4,ly+4);
    ctx.restore();
  }
  ctx.save();
  ctx.font='700 17px Poppins,Arial,sans-serif'; ctx.textAlign='center'; ctx.textBaseline='middle';
  const pw=ctx.measureText(cc.lbl).width+28, ph=26, py=ly+lh+6;
  ctx.fillStyle=cc.col; ctx.fillRect(cx-pw/2,py,pw,ph);
  ctx.fillStyle='#fff'; ctx.fillText(cc.lbl,cx,py+ph/2);
  ctx.restore();
}

function wrapText(ctx,text,maxW){
  if(!text)return[];
  const words=text.split(' '),lines=[];let cur='';
  words.forEach(w=>{const t=cur?cur+' '+w:w;if(ctx.measureText(t).width<=maxW)cur=t;else{if(cur)lines.push(cur);cur=w;}});
  if(cur)lines.push(cur);return lines;
}

